import 'package:flutter/material.dart'; import 'package:flutter_test/flutter_test.dart'; void main() { group('QR Pairing', () { testWidgets('shows tabs for My QR and Scan', (tester) async { await tester.pumpWidget(MaterialApp(home: DefaultTabController(length: 2, child: Scaffold(appBar: AppBar(bottom: const TabBar(tabs: [Tab(text: 'My QR Code'), Tab(text: 'Scan Code')])), body: const TabBarView(children: [Center(child: Text('QR')), Center(child: Text('Scanner'))]))))); expect(find.text('My QR Code'), findsOneWidget); expect(find.text('Scan Code'), findsOneWidget); }); }); }